  `status` enum('SCHEDULED','IN_PROCESS','AWAITING_CSR_ACTION','QUIZ_PENDING','COMPLETED','FOLLOW_UP_REQUIRED','CLOSED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'SCHEDULED',
